import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { supabase } from '../services/supabaseClient';
import { Plus, Search, Filter, Calendar, Tag, Edit3, Trash2 } from 'lucide-react';
import '../styles/Despesas.css';

const Despesas = () => {
  const [despesas, setDespesas] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const navigate = useNavigate();

  useEffect(() => {
    buscarDespesas();
  }, []);

  async function buscarDespesas() {
    setLoading(true);
    try {
      // Mantendo sua alteração: Buscando todos os Gastos Variáveis
      const { data, error } = await supabase
        .from('compras')
        .select(`
          *,
          categorias (nome, cor)
        `)
        .eq('tipo_despesa', 'Gastos Variáveis')
        .order('data_compra', { ascending: false }); // Ordenando pelos mais recentes

      if (error) throw error;
      setDespesas(data || []);
    } catch (error) {
      console.error("Erro ao carregar despesas:", error);
    } finally {
      setLoading(false);
    }
  }

  const formatarMoeda = (valor) => {
    return Number(valor).toLocaleString('pt-BR', { 
      style: 'currency', 
      currency: 'BRL' 
    });
  };

  const filteredDespesas = despesas.filter(d => 
    d.descricao.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleNovoLancamento = () => {
    navigate('/lancamento');
  };

  // Funções para os botões que apareceram na sua imagem
  const handleEditar = (id) => {
    // Lógica para abrir modal ou navegar para edição
    console.log("Editar item:", id);
  };

  const handleExcluir = async (id) => {
    if (window.confirm("Deseja realmente excluir esta despesa?")) {
      const { error } = await supabase.from('compras').delete().eq('id', id);
      if (!error) buscarDespesas();
    }
  };

  return (
    <div className="desp-premium-wrapper fade-in">
      <aside className="desp-sidebar">
        <div className="desp-panel desp-header-panel">
          <div className="desp-title-area">
            <h1>Despesas</h1>
            <p>Fluxo de caixa e pagamentos à vista</p>
          </div>

          <div className="desp-search-box">
            <Search size={18} />
            <input 
              type="text" 
              placeholder="Buscar despesa..." 
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>

          <button className="btn-new-desp-desktop" onClick={handleNovoLancamento}>
            <Plus size={20} /> Nova Despesa
          </button>
        </div>

        <div className="desp-panel desp-summary-card">
          <span className="summary-label">TOTAL PENDENTE</span>
          <h2 className="summary-value">
            {formatarMoeda(filteredDespesas.reduce((acc, curr) => acc + Number(curr.valor_total), 0))}
          </h2>
        </div>
      </aside>

      <main className="desp-main-content">
        <div className="desp-panel desp-list-panel">
          <div className="list-header">
            <h3>Lançamentos do Mês</h3>
            <Filter size={18} className="icon-secondary" />
          </div>

          <div className="desp-list">
            {loading ? (
              <div className="desp-status">Carregando lançamentos...</div>
            ) : filteredDespesas.length > 0 ? (
              filteredDespesas.map((item) => (
                <div key={item.id} className="desp-item-row">
                  <div className="desp-item-info">
                    <div 
                      className="cat-indicator" 
                      style={{ backgroundColor: item.categorias?.cor || '#22c55e' }}
                    ></div>
                    <div className="desp-details">
                      <span className="desp-desc">{item.descricao}</span>
                      <div className="desp-meta">
                        <span className="meta-tag">
                          <Calendar size={12} /> 
                          {item.data_compra ? new Date(item.data_compra).toLocaleDateString('pt-BR') : 'Sem data'}
                        </span>
                        <span className="meta-tag">
                          <Tag size={12} /> 
                          {item.categorias?.nome || 'Lazer'}
                        </span>
                        <span className="meta-tag forma-pag-tag">
                          {item.forma_pagamento}
                        </span>
                      </div>
                    </div>
                  </div>

                  <div className="desp-item-actions">
                    <span className="desp-value">{formatarMoeda(item.valor_total)}</span>
                    <div className="action-buttons">
                      <button 
                        className="btn-action-outline" 
                        onClick={() => handleEditar(item.id)}
                      >
                        <Edit3 size={16} />
                      </button>
                      <button 
                        className="btn-action-outline delete" 
                        onClick={() => handleExcluir(item.id)}
                      >
                        <Trash2 size={16} />
                      </button>
                    </div>
                  </div>
                </div>
              ))
            ) : (
              <div className="desp-empty">Nenhuma despesa encontrada.</div>
            )}
          </div>
        </div>
      </main>

      <button className="desp-fab" onClick={handleNovoLancamento}>
        <Plus size={24} />
      </button>
    </div>
  );
};

export default Despesas;
